const d = msg.payload;
const capsulaId = d.capsula_id || 'unknown';

msg.payload = {
    method: 'SET',
    path: `/capsulas/${capsulaId}/estado_actual`,
    data: {
        temperatura: d.temperatura,
        humedad: d.humedad,
        co2_ppm: d.co2_ppm,
        luz_lux: d.luz_lux,
        temp_sustrato: d.temp_sustrato,
        especie: d.especie,
        etapa: d.etapa,
        actuadores: d.actuadores,
        timestamp: d.timestamp,
        ultima_actualizacion: new Date().toISOString()
    }
};
return msg;

const a = msg.payload;
const tipo = a.tipo || 'desconocido';
const capsula = a.capsula_id || '?';
const valor = a.valor_actual !== undefined ? parseFloat(a.valor_actual).toFixed(1) : '?';
const umbral = a.umbral !== undefined ? parseFloat(a.umbral).toFixed(1) : '?';
const accion = a.accion || 'ninguna';
const hora = new Date().toLocaleTimeString('es-CO', { timeZone: 'America/Bogota', hour: '2-digit', minute: '2-digit' });

const emojis = {
    temp_critica_max: '🌡️🔴',
    temp_critica_min: '🌡️🔵',
    humedad_critica_min: '💧🔴',
    co2_critico_max: '💨🔴',
    sensor_error: '⚠️'
};
const emoji = emojis[tipo] || '🔔';

msg.payload = {
    chatId: process.env.TELEGRAM_CHAT_ID,
    type: 'message',
    content: `${emoji} *ALERTA — ${capsula.toUpperCase()}*\n` +
             `──────────────────────\n` +
             `Tipo: \`${tipo}\`\n` +
             `Valor actual: *${valor}*\n` +
             `Límite: ${umbral}\n` +
             `Acción: ${accion}\n` +
             `Hora: ${hora}\n` +
             `──────────────────────`,
    options: { parse_mode: 'Markdown' }
};
return msg;

// Contexto compartido: el nodo de sensores actualiza context.global.lastSeen
// cuando recibe datos de cada cápsula.
// Este watchdog verifica que ninguna lleve más de 10 min sin publicar.
const now = Date.now();
const lastSeen = global.get('lastSeen') || {};
const TIMEOUT_MS = 10 * 60 * 1000; // 10 min

const silent = Object.entries(lastSeen)
    .filter(([id, ts]) => (now - ts) > TIMEOUT_MS)
    .map(([id]) => id);

if (silent.length > 0) {
    msg.payload = {
        chatId: process.env.TELEGRAM_CHAT_ID,
        type: 'message',
        content: `⚠️ *SIN DATOS* — Cápsulas sin respuesta (>10 min):\n${silent.map(id => `• ${id}`).join('\n')}`,
        options: { parse_mode: 'Markdown' }
    };
    return msg;
}
return null; // sin alerta si todas están bien

const lastSeen = global.get('lastSeen') || {};
const now = Date.now();
const TIMEOUT_MS = 10 * 60 * 1000;

const activas = Object.entries(lastSeen)
    .filter(([id, ts]) => (now - ts) <= TIMEOUT_MS)
    .map(([id]) => `✅ ${id}`);
const inactivas = Object.entries(lastSeen)
    .filter(([id, ts]) => (now - ts) > TIMEOUT_MS)
    .map(([id]) => `❌ ${id}`);

const fecha = new Date().toLocaleDateString('es-CO', { timeZone: 'America/Bogota', weekday: 'long', day: 'numeric', month: 'long' });

msg.payload = {
    chatId: process.env.TELEGRAM_CHAT_ID,
    type: 'message',
    content: `☀️ *Buenos días — Bichongos*\n${fecha}\n\n` +
             `*Cápsulas activas (${activas.length}):*\n${activas.join('\n') || 'Ninguna'}\n\n` +
             (inactivas.length > 0 ? `*Sin datos (${inactivas.length}):*\n${inactivas.join('\n')}` : ''),
    options: { parse_mode: 'Markdown' }
};
return msg;

const d = msg.payload;
if (d && d.capsula_id) {
    const lastSeen = global.get('lastSeen') || {};
    lastSeen[d.capsula_id] = Date.now();
    global.set('lastSeen', lastSeen);
}
return msg;
